    fun d(tag: String = DEFAULT_TAG, message: String) = logChunks(Log.DEBUG, tag, message, null)
    fun i(tag: String = DEFAULT_TAG, message: String) = logChunks(Log.INFO, tag, message, null)
    fun w(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) = logChunks(Log.WARN, tag, message, throwable)
    fun e(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) = logChunks(Log.ERROR, tag, message, throwable)

