                Log.INFO -> Timber.tag(tag).i(fullMessage)
                Log.WARN -> Timber.tag(tag).w(fullMessage)
                Log.ERROR -> Timber.tag(tag).e(fullMessage)
                else -> Timber.tag(tag).d(fullMessage)
            }
            return
        }

        var index = 0
        while (index < fullMessage.length) {
            val end = (index + MAX_LOG_CHUNK_SIZE).coerceAtMost(fullMessage.length)
            val chunk = fullMessage.substring(index, end)
            when (priority) {
                Log.VERBOSE -> Timber.tag(tag).v(chunk)
                Log.DEBUG -> Timber.tag(tag).d(chunk)
                Log.INFO -> Timber.tag(tag).i(chunk)
                Log.WARN -> Timber.tag(tag).w(chunk)
                Log.ERROR -> Timber.tag(tag).e(chunk)
                else -> Timber.tag(tag).d(chunk)
            }
            index = end
        }
    }

    private fun stringify(value: Any?): String {
