class HttpLoggingInterceptor(
    private val logHeaders: Boolean = true,
    private val logRequestBody: Boolean = true,
    private val logResponseBody: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()

        val requestLog = buildString {
            appendLine("HTTP_REQUEST")
            appendLine("url=${request.url}")
            appendLine("method=${request.method}")
            appendLine("headers=${if (logHeaders) headersToMultilineString(request.headers) else "disabled"}")
            appendLine("body=${if (logRequestBody) requestBodyToString(request.body) else "disabled"}")
        }
        AppLogger.v("ApiLogger", requestLog)

        val startNs = System.nanoTime()
        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)

            val responseBody = response.body
            val source = responseBody?.source()
            source?.request(Long.MAX_VALUE)
            val buffer = source?.buffer

            val responseContentType = responseBody?.contentType()
            val responseBodyString = if (logResponseBody) {
                buffer?.clone()?.readString(charset(responseContentType)) ?: "null"
            } else {
                "disabled"
            }

            val responseLog = buildString {
                appendLine("HTTP_RESPONSE")
                appendLine("url=${response.request.url}")
                appendLine("code=${response.code}")
                appendLine("message=${response.message}")
                appendLine("protocol=${response.protocol}")
                appendLine("durationMs=$tookMs")
                appendLine("headers=${if (logHeaders) headersToMultilineString(response.headers) else "disabled"}")
                appendLine("body=$responseBodyString")
            }
            AppLogger.v("ApiLogger", responseLog)
            response
        } catch (e: Exception) {
            val errorLog = buildString {
                appendLine("HTTP_ERROR")
                appendLine("url=${request.url}")
                appendLine("method=${request.method}")
                appendLine("headers=${if (logHeaders) headersToMultilineString(request.headers) else "disabled"}")
                appendLine("body=${if (logRequestBody) requestBodyToString(request.body) else "disabled"}")
                appendLine("error=${e.message}")
                appendLine("stacktrace=${Log.getStackTraceString(e)}")
            }
            AppLogger.e("ApiLogger", errorLog, e)
            throw e
        }
    }

    private fun requestBodyToString(body: RequestBody?): String {
        if (body == null) return "null"
        return try {
            val buffer = Buffer()
            body.writeTo(buffer)
            if (isPlaintext(buffer)) {
                buffer.readString(charset(body.contentType()))
            } else {
                "binary ${body.contentType()} (${body.contentLength()} bytes)"
            }
        } catch (e: Exception) {
            "unable_to_read_body: ${e.message}"
        }
    }

    private fun headersToMultilineString(headers: Headers): String {
        if (headers.size == 0) return "{}"
        return buildString {
            appendLine("{")
            for (i in 0 until headers.size) {
                appendLine("${headers.name(i)}: ${headers.value(i)}")
            }
            append("}")
        }
    }

    private fun charset(mediaType: MediaType?): Charset {
        return mediaType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
    }

    private fun isPlaintext(buffer: Buffer): Boolean {
        return try {
            val prefix = Buffer()
            val byteCount = minOf(buffer.size, 64)
            buffer.copyTo(prefix, 0, byteCount)
            for (i in 0 until 16) {
                if (prefix.exhausted()) break
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) {
                    return false
                }
            }
            true
        } catch (_: EOFException) {
            false
        }
    }
}

object LoggingOkHttpFactory {
    fun create(clientBuilder: OkHttpClient.Builder = OkHttpClient.Builder()): OkHttpClient {
        return clientBuilder
            .addInterceptor(HttpLoggingInterceptor())
            .build()
    }
}

interface DatabaseQueryLogger {
    fun logQuery(sql: String, args: List<Any?> = emptyList(), durationMs: Long? = null, rowsAffected: Int? = null, source: String? = null)
}

class DefaultDatabaseQueryLogger : DatabaseQueryLogger {
    override fun logQuery(sql: String, args: List<Any?>, durationMs: Long?, rowsAffected: Int?, source: String?) {
        AppLogger.logDatabaseQuery(sql, args, durationMs, rowsAffected, source)
    }
}

