class LoggingUncaughtExceptionHandler(
    private val defaultHandler: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()
) : Thread.UncaughtExceptionHandler {

    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        AppLogger.logException(
            throwable = throwable,
            tag = "CrashLogger",
            context = "Uncaught exception on thread=${thread.name}",
            metadata = mapOf("threadId" to thread.id, "threadState" to thread.state.name)
        )
        defaultHandler?.uncaughtException(thread, throwable)
    }
}

object ProductionLogging {
    fun install() {
        AppLogger.init(enableDebugTree = true)
        Thread.setDefaultUncaughtExceptionHandler(LoggingUncaughtExceptionHandler())
    }
}